update health_event
event_type = #{eventType}, content = #{content}, event_time = #{eventTime}, is_public = #{isPublic}, updated_time = #{updatedTime},
where user_id = #{userId} and id = #{id}

mapper.select:
select * from health_event


        event_type like concat('%',#{eventType},'%')


        and event_time between #{eventTimeBegan} and #{eventTimeEnd}


        and is_public = #{isPublic}

         and user_id = #{userId}

order by created_time desc
